const BY_ID = new Map<string, Equipment>(EQUIPMENT.map((e) => [e.id, e]));

export function getEquipment(id: string): Equipment | undefined {
  return BY_ID.get(id);
}

// Seed helper: returns a fresh Record<string, Equipment> cloned from the static
// catalog. Used by demoSeed (factory) and storage migration (v5→v6). Each call
// produces independent Equipment objects so callers never share references
// with the static module-level data.
export function seedEquipmentLibrary(): Record<string, Equipment> {
  const out: Record<string, Equipment> = {};
  for (const e of EQUIPMENT) {
    out[e.id] = {
      ...e,
      tags: e.tags ? [...e.tags] : undefined,
    };
  }
  return out;
}
